const express = require('express');
const axios = require('axios');
const morgan = require('morgan');

const app = express();
const PORT = process.env.PORT || 3000;
const BACKEND_SERVICES = {
    service1: 'http://localhost:4000',
    service2: 'http://localhost:5000',
};

app.use(morgan('combined'));

app.use((req, res, next) => {
    const apiKey = req.query.api_key;
    if (!apiKey) {
        return res.status(401).json({ error: 'API key is required' });
    }
    req.headers['x-api-key'] = apiKey;
    console.log(`Request to ${req.url} with API key: ${apiKey}`);
    next();
});

app.use('/service1', (req, res) => {
    const url = `${BACKEND_SERVICES.service1}${req.originalUrl}`;
    axios({ method: req.method, url, headers: req.headers, data: req.body })
        .then(response => res.status(response.status).json(response.data))
        .catch(error => res.status(error.response ? error.response.status : 500).json({ error: error.message }));
});

app.use('/service2', (req, res) => {
    const url = `${BACKEND_SERVICES.service2}${req.originalUrl}`;
    axios({ method: req.method, url, headers: req.headers, data: req.body })
        .then(response => res.status(response.status).json(response.data))
        .catch(error => res.status(error.response ? error.response.status : 500).json({ error: error.message }));
});

app.listen(PORT, () => {
    console.log(`API Gateway running on port ${PORT}`);
});